package ru.kryuch.krtg.searcher.controller;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RequestParam;import org.springframework.web.servlet.mvc.support.RedirectAttributes;import ru.kryuch.krtg.searcher.dto.ChatInfo;import ru.kryuch.krtg.searcher.service.ChatExportService;import ru.kryuch.krtg.searcher.service.ChatService;import java.util.List;import java.util.stream.Collectors;@Controller@RequiredArgsConstructor@RequestMapping("/upload")public class UploadController {    private final ChatService chatService;    @GetMapping("/")    public String list(Model model) {        model.addAttribute("text", "");        model.addAttribute("page", "upload");        if (model.containsAttribute("successMessage")) {            model.addAttribute("successMessage", model.getAttribute("successMessage"));        }        if (model.containsAttribute("error")) {            model.addAttribute("error", model.getAttribute("error"));        }        return "index";    }    @PostMapping("/")    public String add(@RequestParam("text") String text,                      RedirectAttributes redirectAttributes) {        if (text == null || text.trim().isEmpty()) {            redirectAttributes.addFlashAttribute("error", "Текст не может быть пустым");            return "redirect:/upload/";        }        List<ChatInfo> chats = chatService.createNewContacts(text);        String successMessage = "Текст отправлен контактам: " +                chats.stream()                        .filter(chatInfo -> chatInfo.getStatus().equals(0) || chatInfo.getStatus().equals(13))                        .map(ChatInfo::getName)                        .collect(Collectors.joining(", "));        String errorMessage = "Текст не отправлен контактам: " +                chats.stream()                        .filter(chatInfo -> chatInfo.getStatus().equals(4) || chatInfo.getStatus().equals(12))                        .map(ChatInfo::getName)                        .collect(Collectors.joining(", "));        redirectAttributes.addFlashAttribute("successMessage", successMessage);        redirectAttributes.addFlashAttribute("error", successMessage);        return "redirect:/upload/";    }}